  <li>
    <button
      onClick={onClick}
      className={`flex items-center w-full px-4 py-3 rounded-lg text-left transition-all duration-200 ${
        isActive 
          ? 'bg-orange-500 text-white shadow-md font-bold' 
          : 'text-slate-600 hover:bg-slate-50 hover:text-orange-600'
      }`}
    >
      <span className="h-6 w-6"><Icon className={isActive ? "text-white" : "text-slate-500"} /></span>
      <span className="ml-3 text-[14px]">{label}</span>
    </button>
  </li>
);

const App = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [appLogoUrl, setAppLogoUrl] = useState<string | null>(null);

  // App Data State
  const [users, setUsers] = useState<User[]>([]);
  const [properties, setProperties] = useState<Property[]>([]);
  const [visits, setVisits] = useState<any[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [dailyLogs, setDailyLogs] = useState<DailyLog[]>([]);
  const [captaciones, setCaptaciones] = useState<any[]>([]);
  const [resources, setResources] = useState<any[]>([]);
  const [formats, setFormats] = useState<any[]>([]);

  // UI State
  const [activeView, setActiveView] = useState('dashboard');
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [selectedCaptacionId, setSelectedCaptacionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);

  // Property CRUD State
  const [isPropertyModalOpen, setIsPropertyModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [propertyToDelete, setPropertyToDelete] = useState<Property | null>(null);

  const fetchData = useCallback(async () => {
    try {
      console.log("🔄 Sincronizando con base de datos real...");

      const { data: propData, error: pErr } = await supabase
        .from('properties')
        .select('*')
        .order('created_at', { ascending: false });

      if (pErr) throw pErr;

      // Mapeador robusto basado en el screenshot del Table Editor
      const mappedProperties = (propData || []).map((p: any): Property => ({
        id: p.id,
        created_by: p.created_by,
        name: p.name || 'Sin nombre',
        address: p.address || 'Sin dirección',
        price: Number(p.price) || 0,
        bedrooms: Number(p.bedrooms) || 0,
        bathrooms: Number(p.bathrooms) || 0,
        squareMeters: Number(p.square_meters || p.squareMeters) || 0,
        builtSquareMeters: Number(p.built_square_meters || p.builtSquareMeters) || 0,
        description: p.description || '',
        imageUrl: p.image_url || p.imageUrl || 'https://via.placeholder.com/400x300?text=Sin+Imagen',
        gallery: p.gallery || [],
        latitude: Number(p.latitude) || -12.046,
        longitude: Number(p.longitude) || -77.042,
        propertyIdNumber: p.property_id_number || p.propertyIdNumber || String(p.id).substring(0, 8).toUpperCase(),
        propertyType: (p.property_type || p.propertyType || PropertyType.CASA) as PropertyType,
        status: (p.status || PropertySaleStatus.AVAILABLE) as PropertySaleStatus,
        trafficLight: (p.traffic_light || p.trafficLight || PropertyTrafficLight.GREEN) as PropertyTrafficLight,
        trafficLightReason: p.traffic_light_reason || p.trafficLightReason || '',
        listingType: (p.listing_type || p.listingType || ListingType.VENTA) as ListingType,
        currency: (p.currency || Currency.USD) as Currency,
        propertyDocuments: p.property_documents || p.propertyDocuments || [],
        sold_by_worker_id: p.sold_by_worker_id || null
      }));

      setProperties(mappedProperties);

      // Carga paralela del resto de datos
      const [
        { data: usersData },
        { data: visitData },
        { data: taskData },
        { data: notifData },
        { data: logsData },
        { data: captData },
        { data: resData },
        { data: formatData },
        { data: settingsData }
      ] = await Promise.all([
        supabase.from('users').select('*'),
        supabase.from('visits').select('*'),
        supabase.from('tasks').select('*'),
        supabase.from('notifications').select('*'),
        supabase.from('daily_logs').select('*'),
        supabase.from('captaciones').select('*'),
        supabase.from('training_resources').select('*'),
        supabase.from('formats').select('*'),
        supabase.from('app_settings').select('*').eq('id', 'app_logo_url').maybeSingle()
      ]);

      setUsers(usersData || []);
      setVisits(visitData || []);
      setTasks(taskData || []);
      setNotifications((notifData || []).map(n => ({ ...n, timestamp: new Date(n.timestamp) })));
      setDailyLogs(logsData || []);
      setCaptaciones(captData || []);
      setResources(resData || []);
      setFormats(formatData || []);
      if (settingsData) setAppLogoUrl(settingsData.value);
      setError(null);
    } catch (err: any) {
      console.error("❌ Error en fetchData:", err);
      setError(formatSupabaseError(err));
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (!session) setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session) {
      const init = async () => {
        setLoading(true);
        try {
          const profile = await getProfileForUser(session.user);
          setCurrentUser(profile || { id: session.user.id, email: session.user.email!, name: 'Usuario', role: UserRole.WORKER });
          await fetchData();
        } finally {
          setLoading(false);
        }
      };
      init();
    } else {
      setLoading(false);
    }
  }, [session, fetchData]);

  const handleSaveProperty = async (propertyData: any) => {
    try {
      const dbData = {
          ...propertyData,
          square_meters: propertyData.squareMeters,
          built_square_meters: propertyData.builtSquareMeters,
          property_id_number: propertyData.propertyIdNumber,
          image_url: propertyData.imageUrl,
          property_type: propertyData.propertyType,
          listing_type: propertyData.listingType,
          traffic_light: propertyData.trafficLight,
          traffic_light_reason: propertyData.trafficLightReason,
          property_documents: propertyData.propertyDocuments,
          created_by: editingProperty ? editingProperty.created_by : currentUser?.id 
      };
      delete dbData.squareMeters; delete dbData.builtSquareMeters; delete dbData.propertyIdNumber;
      delete dbData.imageUrl; delete dbData.propertyType; delete dbData.listingType;
      delete dbData.trafficLight; delete dbData.trafficLightReason; delete dbData.propertyDocuments;

      const { error } = await supabase.from('properties').upsert(dbData);
      if (error) throw error;
      setIsPropertyModalOpen(false);
      setEditingProperty(null);
      await fetchData();
    } catch (err: any) {
      alert("Error al guardar: " + formatSupabaseError(err));
    }
  };

  const handleDeleteProperty = async () => {
    if (!propertyToDelete) return;
    try {
      const { error } = await supabase.from('properties').delete().eq('id', propertyToDelete.id);
      if (error) throw error;
      setPropertyToDelete(null);
      await fetchData();
    } catch (err: any) {
      alert("Error al eliminar: " + formatSupabaseError(err));
    }
  };

  const renderContent = () => {
    if (selectedPropertyId) {
      const prop = properties.find(p => p.id === selectedPropertyId);
      if (prop) return <PropertyDetails property={prop} visits={visits.filter(v => v.propertyId === prop.id)} tasks={tasks.filter(t => t.propertyId === prop.id)} users={users} currentUser={currentUser!} onBack={() => setSelectedPropertyId(null)} onSelectVisit={() => {}} onOpenAddVisitModalForProperty={() => {}} onCompleteTask={async (id) => { await supabase.from('tasks').update({ status: TaskStatus.COMPLETED }).eq('id', id); fetchData(); }} onOpenVisitEditor={() => {}} />;
