  };

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-slate-50 font-medium text-slate-600">Cargando datos...</div>;
  if (!session || !currentUser) return <Login logoUrl={appLogoUrl || undefined} />;

  return (
    <div className="min-h-screen flex bg-slate-100 text-slate-900">
      <aside className="hidden md:flex flex-col w-64 bg-white border-r border-slate-200 shadow-sm">
        <div className="p-6 border-b border-slate-50">
          <h1 className="text-2xl font-bold text-orange-500">Aquivivir</h1>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Real Estate CRM</p>
        </div>
        <nav className="flex-1 px-4 py-6 space-y-1">
          <NavItem icon={CogIcon} label="Dashboard" isActive={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} />
          <NavItem icon={BuildingOfficeIcon} label="Propiedades" isActive={activeView === 'properties'} onClick={() => setActiveView('properties')} />
          <NavItem icon={CalendarDaysIcon} label="Calendario" isActive={activeView === 'calendar'} onClick={() => setActiveView('calendar')} />
          <NavItem icon={ClipboardDocumentCheckIcon} label="Captaciones" isActive={activeView === 'captaciones'} onClick={() => setActiveView('captaciones')} />
          <NavItem icon={ClipboardDocumentListIcon} label="Bitácora" isActive={activeView === 'binnacle'} onClick={() => setActiveView('binnacle')} />
          {currentUser.role === UserRole.ADMIN && <NavItem icon={UserIcon} label="Usuarios" isActive={activeView === 'users'} onClick={() => setActiveView('users')} />}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        <Header currentUser={currentUser} logoUrl={appLogoUrl} onLogout={() => supabase.auth.signOut()} unreadCount={0} onToggleNotifications={() => setIsNotificationsOpen(true)} onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8 max-w-7xl mx-auto w-full">
          {renderContent()}
        </main>
      </div>

      {isPropertyModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex justify-center items-center p-4 backdrop-blur-sm">
          <div className="max-w-4xl w-full">
            <PropertyForm initialData={editingProperty} workers={users.filter(u => u.role === UserRole.WORKER)} onSubmit={handleSaveProperty} onCancel={() => setIsPropertyModalOpen(false)} />
          </div>
        </div>
      )}

      {propertyToDelete && (
        <ConfirmationModal 
          title="Eliminar Propiedad" 
          message={`¿Estás seguro de que deseas eliminar "${propertyToDelete.name}"? Esta acción no se puede deshacer y borrará todos los datos asociados.`} 
          onConfirm={handleDeleteProperty} 
          onCancel={() => setPropertyToDelete(null)} 
          confirmButtonText="Eliminar permanentemente" 
        />
      )}
    </div>
  );
};

export default App;
